"use client";

type Insights = {
  mostLoved: { name: string; count: number } | null;
  nachoType: { name: string; count: number } | null;
  hotCold: { name: string; highRank: number; lowRank: number } | null;
  bestBud: { displayName: string; matchPercent: number } | null;
};

function InsightRow({
  emoji,
  title,
  subtitle,
  value,
  detail,
}: {
  emoji: string;
  title: string;
  subtitle: string;
  value: string;
  detail: string;
}) {
  return (
    <div style={{ background: "#FFFCF5", borderRadius: 20, padding: "14px 18px", display: "flex", flexDirection: "column", gap: 8 }}>
      <p style={{ color: "#FE392D", fontWeight: 700, fontSize: 15, textAlign: "center", margin: 0 }}>
        {emoji}&nbsp;&nbsp;{title}&nbsp;&nbsp;{emoji}
      </p>
      <p style={{ color: "#646464", fontSize: 11, textAlign: "center", margin: 0 }}>{subtitle}</p>
      <div style={{ background: "rgba(252,204,117,0.2)", border: "2px solid #FCCC75", borderRadius: 12, padding: "10px 14px", color: "#646464", fontSize: 14, textAlign: "center" }}>
        {value}
      </div>
      <div style={{ background: "#FCCC75", borderRadius: 999, padding: "4px 12px", color: "#646464", fontSize: 11, textAlign: "center", alignSelf: "center" }}>
        {detail}
      </div>
    </div>
  );
}

export function FlavorJourneyShareCard({
  restaurantName,
  insights,
  cardRef,
}: {
  restaurantName: string;
  insights: Insights;
  cardRef: React.RefObject<HTMLDivElement>;
}) {
  return (
    <div
      ref={cardRef}
      style={{
        width: 360,
        height: 640,
        background: "#FFF8E8",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        padding: "32px 24px 24px",
        fontFamily: "Poppins, sans-serif",
        boxSizing: "border-box",
        gap: 12,
      }}
    >
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img src="/logo_long_red.png" alt="playte" style={{ width: 140, objectFit: "contain" }} />
      <p style={{ color: "#9CA3AF", fontSize: 12, fontStyle: "italic", margin: 0 }}>{restaurantName}</p>
      <p style={{ color: "#FE392D", fontSize: 24, fontWeight: 700, margin: 0 }}>Flavor Journey</p>

      <div style={{ display: "flex", flexDirection: "column", gap: 10, width: "100%" }}>
        {insights.mostLoved && (
          <InsightRow emoji="😍" title="most loved" subtitle="clean plate club" value={insights.mostLoved.name} detail={`ranked #1 by ${insights.mostLoved.count}`} />
        )}
        {insights.nachoType && (
          <InsightRow emoji="🤤" title="nacho type" subtitle="zero out of ten, respectfully" value={insights.nachoType.name} detail={`ranked last by ${insights.nachoType.count}`} />
        )}
        {insights.hotCold && (
          <InsightRow emoji="😐" title="hot & cold" subtitle="most controversial playte debate" value={insights.hotCold.name} detail={`as high as #${insights.hotCold.highRank}, as low as #${insights.hotCold.lowRank}`} />
        )}
        {insights.bestBud && (
          <InsightRow emoji="👯" title="best (taste) buds" subtitle="you should share next time" value={insights.bestBud.displayName} detail={`${insights.bestBud.matchPercent}% match`} />
        )}
      </div>

      <p style={{ color: "#9CA3AF", fontSize: 10, marginTop: "auto" }}>made with playte</p>
    </div>
  );
}
